"use client";

/**
 * FormSection Component
 *
 * A form section for settings pages and structured form layouts.
 * Optimized for Product Mode with clear hierarchy and efficient space usage.
 *
 * @example
 * ```tsx
 * <FormSection
 *   title="Profile Information"
 *   description="Update your personal details"
 *   actions={<Button>Save</Button>}
 * >
 *   <FormSection.Group columns={2}>
 *     <Field label="First Name" type="text" />
 *     <Field label="Last Name" type="text" />
 *   </FormSection.Group>
 *   <Field label="Email" type="email" />
 * </FormSection>
 * ```
 */

import { forwardRef, useState } from "react";
import { ChevronDown } from "lucide-react";
import type {
  FormSectionProps,
  FormSectionGroupProps,
  FormSectionActionsProps,
} from "./FormSection.types";
import styles from "./FormSection.module.css";

// Sub-component: Group
const FormSectionGroup = forwardRef<HTMLDivElement, FormSectionGroupProps>(
  ({ label, helpText, children, columns = 1, className, ...rest }, ref) => {
    const classNames = [styles.group, styles[`columns-${columns}`], className]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {label && <div className={styles.groupLabel}>{label}</div>}
        <div className={styles.groupFields}>{children}</div>
        {helpText && <div className={styles.groupHelp}>{helpText}</div>}
      </div>
    );
  },
);

FormSectionGroup.displayName = "FormSection.Group";

// Sub-component: Actions
const FormSectionActions = forwardRef<HTMLDivElement, FormSectionActionsProps>(
  ({ children, align = "end", className, ...rest }, ref) => {
    const classNames = [styles.actions, styles[`align-${align}`], className]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {children}
      </div>
    );
  },
);

FormSectionActions.displayName = "FormSection.Actions";

// Main component
const FormSectionBase = forwardRef<HTMLDivElement, FormSectionProps>(
  (
    {
      title,
      description,
      children,
      actions,
      collapsible = false,
      defaultCollapsed = false,
      divider = false,
      variant = "default",
      icon,
      disabled = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const [collapsed, setCollapsed] = useState(defaultCollapsed);

    const classNames = [
      styles.formSection,
      styles[`variant-${variant}`],
      divider && styles.divider,
      disabled && styles.disabled,
      collapsible && styles.collapsible,
      collapsed && styles.collapsed,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    const handleToggle = () => {
      if (collapsible) {
        setCollapsed(!collapsed);
      }
    };

    const HeaderTag = collapsible ? "button" : "div";
    const headerProps = collapsible
      ? {
          type: "button" as const,
          onClick: handleToggle,
          "aria-expanded": !collapsed,
        }
      : {};

    // Only render header if there's content to show
    const hasHeader = title || icon || collapsible;

    return (
      <div ref={ref} className={classNames} {...rest}>
        {hasHeader && (
          <HeaderTag className={styles.header} {...headerProps}>
            <div className={styles.headerContent}>
              {icon && <span className={styles.icon}>{icon}</span>}
              {(title || description) && (
                <div className={styles.headerText}>
                  {title && <h3 className={styles.title}>{title}</h3>}
                  {description && (
                    <p className={styles.description}>{description}</p>
                  )}
                </div>
              )}
            </div>
            {collapsible && (
              <ChevronDown
                size={20}
                className={`${styles.collapseIcon} ${collapsed ? styles.iconCollapsed : ""}`}
              />
            )}
          </HeaderTag>
        )}

        {(!collapsible || !collapsed) && (
          <div className={styles.content}>
            <div className={styles.fields}>{children}</div>
            {actions && <div className={styles.actionsWrapper}>{actions}</div>}
          </div>
        )}
      </div>
    );
  },
);

FormSectionBase.displayName = "FormSection";

// Compose with sub-components
export const FormSection = Object.assign(FormSectionBase, {
  Group: FormSectionGroup,
  Actions: FormSectionActions,
});

/**
 * FormSection Component Types
 *
 * Type definitions for the Orion FormSection section component.
 * Designed for Product Mode (SaaS dashboards) settings and form layouts.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * FormSection visual variant
 */
export type FormSectionVariant = "default" | "card" | "inline";

/**
 * FormSection section props
 *
 * @example
 * ```tsx
 * <FormSection
 *   title="Profile Information"
 *   description="Update your personal details"
 * >
 *   <Field label="Name" type="text" />
 *   <Field label="Email" type="email" />
 * </FormSection>
 * ```
 */
export interface FormSectionProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Section title (optional)
   * If not provided, header is omitted unless collapsible is true
   */
  title?: string;

  /**
   * Description text below title
   */
  description?: string;

  /**
   * Form field children
   */
  children: ReactNode;

  /**
   * Action buttons (save, cancel, etc.)
   */
  actions?: ReactNode;

  /**
   * Make section collapsible
   * @default false
   */
  collapsible?: boolean;

  /**
   * Default collapsed state (only when collapsible)
   * @default false
   */
  defaultCollapsed?: boolean;

  /**
   * Show divider below section
   * @default false
   */
  divider?: boolean;

  /**
   * Visual variant
   * - default: Simple layout with border
   * - card: Wrapped in card container
   * - inline: Side-by-side title/fields layout
   * @default 'default'
   */
  variant?: FormSectionVariant;

  /**
   * Custom icon for section header
   */
  icon?: ReactNode;

  /**
   * Disable all fields in section
   * @default false
   */
  disabled?: boolean;
}

/**
 * FormSection.Group props for grouping related fields
 */
export interface FormSectionGroupProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Group label
   */
  label?: string;

  /**
   * Help text for the group
   */
  helpText?: string;

  /**
   * Field children
   */
  children: ReactNode;

  /**
   * Number of columns for field layout
   * @default 1
   */
  columns?: 1 | 2 | 3;
}

/**
 * FormSection.Actions props for action button group
 */
export interface FormSectionActionsProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Action button children
   */
  children: ReactNode;

  /**
   * Alignment of actions
   * @default 'end'
   */
  align?: "start" | "center" | "end" | "between";
}

/**
 * FormSection Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Clean, efficient layout for settings and form pages.
 */

.formSection {
  display: flex;
  flex-direction: column;
}

.divider {
  border-bottom: 1px solid var(--border-subtle);
  padding-bottom: var(--mode-spacing-block);
  margin-bottom: var(--mode-spacing-block);
}

.disabled {
  opacity: 0.6;
  pointer-events: none;
}

/* ============================================================================
 * HEADER
 * ============================================================================ */

.header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--spacing-4);
  width: 100%;
  text-align: left;
  background: none;
  border: none;
  padding: 0;
  margin-bottom: var(--mode-spacing-element);
}

.collapsible .header {
  cursor: pointer;
  padding: var(--spacing-3);
  margin: calc(var(--spacing-3) * -1);
  margin-bottom: var(--spacing-3);
  border-radius: var(--radius-sm);
  transition: background-color var(--mode-hover-duration);
}

.collapsible .header:hover {
  background: var(--surface-subtle);
}

.collapsed .header {
  margin-bottom: 0;
}

.headerContent {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-3);
}

.headerText {
  flex: 1;
  min-width: 0;
}

.icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  background: var(--surface-subtle);
  border-radius: var(--radius-control);
  color: var(--interactive-primary);
  flex-shrink: 0;
}

.title {
  font-family: var(--font-secondary);
  font-size: var(--font-size-16);
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  margin: 0;
  line-height: var(--line-height-tight);
}

.description {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  margin: var(--spacing-1) 0 0 0;
  line-height: var(--line-height-relaxed);
}

.collapseIcon {
  color: var(--text-tertiary);
  flex-shrink: 0;
  transition: transform var(--mode-hover-duration);
}

.iconCollapsed {
  transform: rotate(-90deg);
}

/* ============================================================================
 * CONTENT
 * ============================================================================ */

.content {
  display: flex;
  flex-direction: column;
  gap: var(--mode-spacing-element);
}

.fields {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-4);
}

.actionsWrapper {
  margin-top: var(--spacing-4);
  padding-top: var(--spacing-4);
  border-top: 1px solid var(--border-subtle);
}

/* ============================================================================
 * GROUP SUB-COMPONENT
 * ============================================================================ */

.group {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.groupLabel {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
}

.groupFields {
  display: grid;
  gap: var(--spacing-4);
}

.columns-1 .groupFields {
  grid-template-columns: 1fr;
}

.columns-2 .groupFields {
  grid-template-columns: repeat(2, 1fr);
}

.columns-3 .groupFields {
  grid-template-columns: repeat(3, 1fr);
}

.groupHelp {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-tertiary);
  line-height: var(--line-height-relaxed);
}

/* ============================================================================
 * ACTIONS SUB-COMPONENT
 * ============================================================================ */

.actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-3);
  flex-wrap: wrap;
}

.align-start {
  justify-content: flex-start;
}

.align-center {
  justify-content: center;
}

.align-end {
  justify-content: flex-end;
}

.align-between {
  justify-content: space-between;
}

/* ============================================================================
 * VARIANT: CARD
 * ============================================================================ */

.variant-card {
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-container);
  padding: var(--mode-spacing-element);
}

.variant-card .header {
  margin-bottom: var(--spacing-4);
}

.variant-card .actionsWrapper {
  margin-top: var(--spacing-6);
}

/* ============================================================================
 * VARIANT: INLINE
 * ============================================================================ */

.variant-inline {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: var(--spacing-8);
}

.variant-inline .header {
  margin-bottom: 0;
  position: sticky;
  top: var(--spacing-4);
  align-self: start;
}

.variant-inline .content {
  flex: 1;
}

.variant-inline .collapseIcon {
  display: none;
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 768px) {
  .variant-inline {
    grid-template-columns: 1fr;
    gap: var(--spacing-4);
  }

  .variant-inline .header {
    position: static;
  }

  .columns-2 .groupFields,
  .columns-3 .groupFields {
    grid-template-columns: 1fr;
  }
}

export { FormSection } from "./FormSection";
export type {
  FormSectionProps,
  FormSectionVariant,
  FormSectionGroupProps,
  FormSectionActionsProps,
} from "./FormSection.types";
